import React,
{ useState, useEffect } from 'react';
import BudgetBuilder from './components/BudgetBuilder';
import AdminPanel from './components/AdminPanel';
import FichasPanel from './components/FichasPanel';
import SettingsPanel from './components/SettingsPanel';
import SavedBudgets from './components/SavedBudgets';
import Dashboard from './components/Dashboard';
import SummaryPanel from './components/SummaryPanel';
import ToastContainer from './components/ui/Toast';
import { useData } from './contexts/DataContext';
import HelpPanel from './components/HelpPanel';
import CostAnalysisPanel from './components/CostAnalysisPanel';
import { Shirt, FileText, Wrench, Settings, BookOpen, LayoutDashboard, LogOut, LifeBuoy, Calculator } from 'lucide-react';
import { supabase } from './services/supabaseClient';
import type { User } from '@supabase/supabase-js';
import type { View } from './types';


const App: React.FC = () => {
  const [activeView, setActiveView] = useState<View>('dashboard');
  const [user, setUser] = useState<User | null>(null);
  const { currentOrcamento, parametros } = useData();

  useEffect(() => {
    supabase.auth.getUser().then(({ data: { user } }) => {
      setUser(user);
    });
  }, []);

  const handleLogout = async () => {
    await supabase.auth.signOut();
  };

  const navItems = [
    { id: 'dashboard', label: 'Visão Geral', icon: <LayoutDashboard size={20} /> },
    { id: 'builder', label: 'Criar Orçamento', icon: <Shirt size={20} /> },
    { id: 'saved', label: 'Orçamentos', icon: <FileText size={20} /> },
    { id: 'fichas', label: 'Fichas Técnicas', icon: <BookOpen size={20} /> },
    { id: 'cost_analysis', label: 'Análise de Custos', icon: <Calculator size={20} /> },
    { id: 'admin', label: 'Cadastros', icon: <Wrench size={20} /> },
    { id: 'settings', label: 'Configurações', icon: <Settings size={20} /> },
  ];

  const bottomNavItems = [
    { id: 'help', label: 'Ajuda', icon: <LifeBuoy size={20} /> },
  ];

  const renderView = () => {
    switch (activeView) {
      case 'dashboard':
        return <Dashboard />;
      case 'builder':
        return <BudgetBuilder />;
      case 'saved':
        return <SavedBudgets setActiveView={setActiveView} />;
      case 'fichas':
        return <FichasPanel />;
      case 'cost_analysis':
        return <CostAnalysisPanel />;
      case 'admin':
        return <AdminPanel />;
      case 'settings':
        return <SettingsPanel />;
      case 'help':
        return <HelpPanel />;
      default:
        return <Dashboard />;
    }
  };

  const calculateTotals = () => {
    const totalReceita = currentOrcamento.itens.reduce((sum, item) => sum + (item.precoUnitario * item.quantidade), 0);
    const totalReceitaTabela = currentOrcamento.itens.reduce((sum, item) => sum + (item.precoTabelaUnitario * item.quantidade), 0);
    const totalCustoProducao = currentOrcamento.itens.reduce((sum, item) => sum + (item.custoUnitario * item.quantidade), 0);

    const taxaImposto = parametros?.taxa_imposto || 0;
    const taxaComissao = parametros?.taxa_comissao || 0;
    const taxaTotal = taxaImposto + taxaComissao;

    const totalCustosVariaveis = totalReceita * taxaTotal;
    const totalLucro = totalReceita - totalCustoProducao - totalCustosVariaveis;
    return { totalReceita, totalReceitaTabela, totalCustoProducao, totalCustosVariaveis, totalLucro };
  };


  return (
    <div className="flex h-screen bg-slate-100 text-slate-800 antialiased">
      <aside className="w-64 bg-slate-900 text-slate-300 flex flex-col shadow-lg z-30">
        <div className="h-20 flex items-center justify-center px-6 border-b border-slate-800">
           <h1 className="text-2xl font-extrabold text-white tracking-wider">
              Uni<span className="text-primary-500">Budget</span>
            </h1>
        </div>
        <nav className="flex-1 p-4 space-y-1.5">
          {navItems.map((item) => (
            <button
              key={item.id}
              onClick={() => setActiveView(item.id as View)}
              className={`w-full flex items-center px-4 py-2.5 text-sm font-semibold rounded-lg transition-colors duration-150 group ${
                activeView === item.id
                  ? 'bg-primary-600 text-white shadow-md'
                  : 'hover:bg-slate-800 hover:text-white'
              }`}
            >
              <span className={`mr-4 ${activeView === item.id ? 'text-white' : 'text-slate-400 group-hover:text-white'}`}>{item.icon}</span>
              {item.label}
            </button>
          ))}
        </nav>
        <div className="p-4 border-t border-slate-800 space-y-1.5">
           {bottomNavItems.map((item) => (
            <button
              key={item.id}
              onClick={() => setActiveView(item.id as View)}
              className={`w-full flex items-center px-4 py-2.5 text-sm font-semibold rounded-lg transition-colors duration-150 group ${
                activeView === item.id
                  ? 'bg-primary-600 text-white'
                  : 'hover:bg-slate-800 hover:text-white'
              }`}
            >
              <span className={`mr-4 ${activeView === item.id ? 'text-white' : 'text-slate-400 group-hover:text-white'}`}>{item.icon}</span>
              {item.label}
            </button>
          ))}
            <div className="pt-2">
                <div className="w-full flex items-center space-x-3 p-2 bg-slate-800/50 rounded-lg">
                    <div className="bg-primary-500 text-white rounded-full h-9 w-9 flex items-center justify-center font-bold text-sm">
                        {user?.email?.charAt(0).toUpperCase()}
                    </div>
                    <div className="text-left flex-1 overflow-hidden">
                        <p className="text-sm font-semibold text-white truncate">{user?.user_metadata.full_name || user?.email}</p>
                    </div>
                    <button onClick={handleLogout} title="Sair" className="p-2 text-slate-400 hover:text-white hover:bg-slate-700 rounded-full transition-colors">
                        <LogOut size={18} />
                    </button>
                </div>
            </div>
        </div>
      </aside>
      <main className={`flex-1 overflow-y-auto relative ${activeView === 'builder' ? 'pb-[88px]' : ''}`}>
        <div className="p-6 md:p-8 animate-fade-in">
          {renderView()}
        </div>
      </main>
      <ToastContainer />
      {activeView === 'builder' && <SummaryPanel totals={calculateTotals()} />}
    </div>
  );
};

export default App;

import React, { useMemo } from 'react';
import { useData } from '../contexts/DataContext';
import { Card, CardHeader, CardTitle } from './ui/Card';
import Spinner from './ui/Spinner';
import EmptyState from './ui/EmptyState';
import { Calculator, Info } from 'lucide-react';

// Helper function
const formatCurrency = (value: number) => value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });

const CostAnalysisPanel: React.FC = () => {
    const { 
        produtosBase, 
        fichasTecnicas, 
        insumos, 
        insumosEspeciais, 
        insumosEspeciaisOpcoes,
        loading 
    } = useData();

    const analysisData = useMemo(() => {
        if (loading || !produtosBase.length) {
            return [];
        }

        // Pre-compute maps for performance
        const fichasByProduct = fichasTecnicas.reduce<Record<number, any[]>>((acc, ft) => {
            if (!acc[ft.produto_base_id]) {
                acc[ft.produto_base_id] = [];
            }
            acc[ft.produto_base_id].push(ft);
            return acc;
        }, {});

        const insumosById = new Map(insumos.map(i => [i.id, i]));
        const optionsBySpecialInput = insumosEspeciaisOpcoes.reduce<Record<number, any[]>>((acc, opt) => {
            if (!acc[opt.insumo_especial_id]) {
                acc[opt.insumo_especial_id] = [];
            }
            acc[opt.insumo_especial_id].push(opt);
            return acc;
        }, {});

        return produtosBase.map(produto => {
            const productFichas = fichasByProduct[produto.id] || [];

            // 1. Calculate base cost from regular insumos
            const baseCost = productFichas
                .filter(ft => ft.insumo_id && ft.quantidade)
                .reduce((sum, ft) => {
                    const insumo = insumosById.get(ft.insumo_id);
                    return sum + ((insumo?.custo_unitario || 0) * (ft.quantidade || 0));
                }, 0);

            // 2. Calculate costs for each special input category
            const specialCosts: Record<number, {min: number, max: number} | null> = {};
            insumosEspeciais.forEach(specialInput => {
                const fichaForItem = productFichas.find(ft => ft.insumo_especial_id === specialInput.id);
                if (!fichaForItem) {
                    specialCosts[specialInput.id] = null; // Product doesn't use this special input
                    return;
                }

                const options = optionsBySpecialInput[specialInput.id] || [];
                if (options.length === 0) {
                    specialCosts[specialInput.id] = { min: baseCost, max: baseCost }; // No options, cost is just base cost
                    return;
                }

                const optionCosts = options.map(opt => {
                    const insumo = insumosById.get(opt.insumo_id);
                    if (!insumo) return [0, 0];

                    const insumoCost = insumo.custo_unitario;

                    if (fichaForItem.quantidade !== null) {
                        const cost = fichaForItem.quantidade * insumoCost;
                        return [cost, cost];
                    } else if (fichaForItem.quantidade_infantil !== null && fichaForItem.quantidade_adulto !== null) {
                        const costInfantil = fichaForItem.quantidade_infantil * insumoCost;
                        const costAdulto = fichaForItem.quantidade_adulto * insumoCost;
                        return [Math.min(costInfantil, costAdulto), Math.max(costInfantil, costAdulto)];
                    }
                    return [0, 0];
                });

                if (optionCosts.length === 0) {
                     specialCosts[specialInput.id] = { min: baseCost, max: baseCost };
                     return;
                }

                const minOptionCost = Math.min(...optionCosts.map(c => c[0]));
                const maxOptionCost = Math.max(...optionCosts.map(c => c[1]));

                specialCosts[specialInput.id] = {
                    min: baseCost + minOptionCost,
                    max: baseCost + maxOptionCost
                };
            });

            return {
                id: produto.id,
                nome: produto.nome,
                baseCost,
                specialCosts,
            };
        });
    }, [produtosBase, fichasTecnicas, insumos, insumosEspeciais, insumosEspeciaisOpcoes, loading]);

    if (loading) {
        return <div className="flex justify-center items-center p-10"><Spinner /></div>;
    }

    return (
        <div className="space-y-6">
            <div>
                <h1 className="text-3xl font-bold text-slate-900">Análise de Custos</h1>
                <p className="text-slate-500 mt-1">Visualize o custo total de cada produto com base nas variações de insumos especiais.</p>
            </div>

            <div className="bg-primary-50 border border-primary-200 text-primary-800 p-4 rounded-lg flex items-start space-x-3">
                <Info size={20} className="flex-shrink-0 mt-0.5"/>
                <div>
                    <h4 className="font-semibold">Como ler esta tabela:</h4>
                    <p className="text-sm">
                        Cada coluna de insumo especial mostra o custo final do produto. Quando um intervalo de valores é exibido (ex: R$ 50,00 - R$ 65,00), ele representa o custo total usando a opção mais barata e a mais cara daquela categoria de insumo.
                    </p>
                </div>
            </div>

            <Card>
                <CardHeader>
                    <CardTitle>Custo Final por Variação de Insumo</CardTitle>
                </CardHeader>
                {analysisData.length === 0 ? (
                    <EmptyState icon={<Calculator size={40}/>} message="Nenhum dado para analisar" description="Cadastre produtos e fichas técnicas para começar." />
                ) : (
                    <div className="overflow-x-auto">
                        <table className="min-w-full">
                            <thead className="bg-slate-50">
                                <tr>
                                    <th className="sticky left-0 bg-slate-50 px-6 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider z-10">Produto</th>
                                    <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Custo Base</th>
                                    {insumosEspeciais.map(is => (
                                        <th key={is.id} className="px-6 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">{is.nome}</th>
                                    ))}
                                </tr>
                            </thead>
                            <tbody className="bg-white divide-y divide-slate-100">
                                {analysisData.map(produto => (
                                    <tr key={produto.id} className="hover:bg-slate-50">
                                        <td className="sticky left-0 bg-white hover:bg-slate-50 px-6 py-4 whitespace-nowrap text-sm font-medium text-slate-900 z-10">{produto.nome}</td>
                                        <td className="px-6 py-4 whitespace-nowrap text-sm text-danger-600 font-semibold">{formatCurrency(produto.baseCost)}</td>
                                        {insumosEspeciais.map(is => {
                                            const costData = produto.specialCosts[is.id];
                                            let displayValue = <span className="text-slate-400">N/A</span>;
                                            if (costData) {
                                                if (Math.abs(costData.min - costData.max) < 0.01) {
                                                    displayValue = <span className="font-semibold text-slate-800">{formatCurrency(costData.min)}</span>;
                                                } else {
                                                    displayValue = (
                                                        <span className="font-semibold text-slate-800">
                                                            {formatCurrency(costData.min)} - {formatCurrency(costData.max)}
                                                        </span>
                                                    );
                                                }
                                            }
                                            return (
                                                <td key={is.id} className="px-6 py-4 whitespace-nowrap text-sm">{displayValue}</td>
                                            );
                                        })}
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                )}
            </Card>
        </div>
    );
};

export default CostAnalysisPanel;

