import React, { useMemo } from 'react';
import { useData } from '../contexts/DataContext';
import { Card, CardHeader, CardTitle } from './ui/Card';
import Spinner from './ui/Spinner';
import EmptyState from './ui/EmptyState';
import { Calculator, Info } from 'lucide-react';
// FIX: Import types for use in accumulator type definitions.
import type { FichaTecnica, InsumoEspecialOpcao } from '../types';

// Helper function
const formatCurrency = (value: number) => value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });

const CostAnalysisPanel: React.FC = () => {
    const { 
        produtosBase, 
        fichasTecnicas, 
        insumos, 
        insumosEspeciais, 
        insumosEspeciaisOpcoes,
        loading 
    } = useData();

    const analysisData = useMemo(() => {
        if (loading || !produtosBase.length) {
            return [];
        }

        // Pre-compute maps for performance
        // FIX: Provide a specific type for the accumulator to avoid 'any' type propagation.
        const fichasByProduct = fichasTecnicas.reduce<Record<number, FichaTecnica[]>>((acc, ft) => {
            if (!acc[ft.produto_base_id]) {
                acc[ft.produto_base_id] = [];
            }
            acc[ft.produto_base_id].push(ft);
            return acc;
        }, {});

        const insumosById = new Map(insumos.map(i => [i.id, i]));
        // FIX: Provide a specific type for the accumulator to avoid 'any' type propagation.
        const optionsBySpecialInput = insumosEspeciaisOpcoes.reduce<Record<number, InsumoEspecialOpcao[]>>((acc, opt) => {
            if (!acc[opt.insumo_especial_id]) {
                acc[opt.insumo_especial_id] = [];
            }
            acc[opt.insumo_especial_id].push(opt);
            return acc;
        }, {});

        return produtosBase.map(produto => {
            const productFichas = fichasByProduct[produto.id] || [];

            // 1. Calculate base cost from regular insumos
            const baseCost = productFichas
                .filter(ft => ft.insumo_id && ft.quantidade)
                .reduce((sum, ft) => {
                    const insumo = insumosById.get(ft.insumo_id!);
                    return sum + ((insumo?.custo_unitario || 0) * (ft.quantidade || 0));
                }, 0);

            // 2. Calculate costs for each special input category
            const specialCosts: Record<number, {min: number, max: number} | null> = {};
            insumosEspeciais.forEach(specialInput => {
                const fichaForItem = productFichas.find(ft => ft.insumo_especial_id === specialInput.id);
                if (!fichaForItem) {
                    specialCosts[specialInput.id] = null; // Product doesn't use this special input
                    return;
                }

                const options = optionsBySpecialInput[specialInput.id] || [];
                if (options.length === 0) {
                    specialCosts[specialInput.id] = { min: baseCost, max: baseCost }; // No options, cost is just base cost
                    return;
                }

                const optionCosts = options.map(opt => {
                    const insumo = insumosById.get(opt.insumo_id);
                    if (!insumo) return [0, 0];

                    const insumoCost = insumo.custo_unitario;

                    if (fichaForItem.quantidade !== null) {
                        const cost = fichaForItem.quantidade * insumoCost;
                        return [cost, cost];
                    } else if (fichaForItem.quantidade_infantil !== null && fichaForItem.quantidade_adulto !== null) {
                        const costInfantil = fichaForItem.quantidade_infantil * insumoCost;
                        const costAdulto = fichaForItem.quantidade_adulto * insumoCost;
                        return [Math.min(costInfantil, costAdulto), Math.max(costInfantil, costAdulto)];
                    }
                    return [0, 0];
                });

                if (optionCosts.length === 0) {
                     specialCosts[specialInput.id] = { min: baseCost, max: baseCost };
                     return;
                }

                const minOptionCost = Math.min(...optionCosts.map(c => c[0]));
                const maxOptionCost = Math.max(...optionCosts.map(c => c[1]));

                specialCosts[specialInput.id] = {
                    min: baseCost + minOptionCost,
                    max: baseCost + maxOptionCost
                };
            });

            return {
                id: produto.id,
                nome: produto.nome,
                baseCost,
                specialCosts,
            };
        });
    }, [produtosBase, fichasTecnicas, insumos, insumosEspeciais, insumosEspeciaisOpcoes, loading]);

    if (loading) {
        return <div className="flex justify-center items-center p-10"><Spinner /></div>;
    }

    return (
        <div className="space-y-6">
            <div>
                <h1 className="text-3xl font-bold text-slate-900">Análise de Custos</h1>
                <p className="text-slate-500 mt-1">Visualize o custo total de cada produto com base nas variações de insumos especiais.</p>
            </div>

            <div className="bg-primary-50 border border-primary-200 text-primary-800 p-4 rounded-lg flex items-start space-x-3">
                <Info size={20} className="flex-shrink-0 mt-0.5"/>
                <div>
                    <h4 className="font-semibold">Como ler esta tabela:</h4>
                    <p className="text-sm">
                        Cada coluna de insumo especial mostra o custo final do produto. Quando um intervalo de valores é exibido (ex: R$ 50,00 - R$ 65,00), ele representa o custo total usando a opção mais barata e a mais cara daquela categoria de insumo.
                    </p>
                </div>
            </div>

            <Card>
                <CardHeader>
                    <CardTitle>Custo Final por Variação de Insumo</CardTitle>
                </CardHeader>
                {analysisData.length === 0 ? (
                    <EmptyState icon={<Calculator size={40}/>} message="Nenhum dado para analisar" description="Cadastre produtos e fichas técnicas para começar." />
                ) : (
                    <div className="overflow-x-auto">
                        <table className="min-w-full">
                            <thead className="bg-slate-50">
                                <tr>
                                    <th className="sticky left-0 bg-slate-50 px-6 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider z-10">Produto</th>
                                    <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Custo Base</th>
                                    {insumosEspeciais.map(is => (
                                        <th key={is.id} className="px-6 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">{is.nome}</th>
                                    ))}
                                </tr>
                            </thead>
                            <tbody className="bg-white divide-y divide-slate-100">
                                {analysisData.map(produto => (
                                    <tr key={produto.id} className="hover:bg-slate-50">
                                        <td className="sticky left-0 bg-white hover:bg-slate-50 px-6 py-4 whitespace-nowrap text-sm font-medium text-slate-900 z-10">{produto.nome}</td>
                                        <td className="px-6 py-4 whitespace-nowrap text-sm text-danger-600 font-semibold">{formatCurrency(produto.baseCost)}</td>
                                        {insumosEspeciais.map(is => {
                                            const costData = produto.specialCosts[is.id];
                                            let displayValue = <span className="text-slate-400">N/A</span>;
                                            if (costData) {
                                                if (Math.abs(costData.min - costData.max) < 0.01) {
                                                    displayValue = <span className="font-semibold text-slate-800">{formatCurrency(costData.min)}</span>;
                                                } else {
                                                    displayValue = (
                                                        <span className="font-semibold text-slate-800">
                                                            {formatCurrency(costData.min)} - {formatCurrency(costData.max)}
                                                        </span>
                                                    );
                                                }
                                            }
                                            return (
                                                <td key={is.id} className="px-6 py-4 whitespace-nowrap text-sm">{displayValue}</td>
                                            );
                                        })}
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                )}
            </Card>
        </div>
    );
};

export default CostAnalysisPanel;

import React, { useMemo, useState } from 'react';
import { useData } from '../contexts/DataContext';
import { Card, CardHeader, CardTitle } from './ui/Card';
import Spinner from './ui/Spinner';
import EmptyState from './ui/EmptyState';
import { Calculator, Info, Filter } from 'lucide-react';
import type { FichaTecnica, InsumoEspecialOpcao } from '../types';

// Helper function
const formatCurrency = (value: number) => value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });

const CostAnalysisPanel: React.FC = () => {
    const { 
        produtosBase, 
        fichasTecnicas, 
        insumos, 
        insumosEspeciais, 
        insumosEspeciaisOpcoes,
        loading 
    } = useData();

    const [selections, setSelections] = useState<Record<number, string>>({});

    const analysisData = useMemo(() => {
        if (loading || !produtosBase.length) {
            return [];
        }

        const fichasByProduct = fichasTecnicas.reduce<Record<number, FichaTecnica[]>>((acc, ft) => {
            if (!acc[ft.produto_base_id]) acc[ft.produto_base_id] = [];
            acc[ft.produto_base_id].push(ft);
            return acc;
        }, {});

        const insumosById = new Map(insumos.map(i => [i.id, i]));

        return produtosBase.map(produto => {
            const productFichas = fichasByProduct[produto.id] || [];

            const baseCost = productFichas
                .filter(ft => ft.insumo_id && ft.quantidade !== null)
                .reduce((sum, ft) => {
                    const insumo = insumosById.get(ft.insumo_id!);
                    return sum + ((insumo?.custo_unitario || 0) * (ft.quantidade || 0));
                }, 0);

            let totalCost = baseCost;
            const specialCostsBreakdown: Record<number, { cost: number; name: string }> = {};

            Object.entries(selections).forEach(([specialInputIdStr, selectedInsumoIdStr]) => {
                if (!selectedInsumoIdStr) return; 

                const specialInputId = parseInt(specialInputIdStr, 10);
                const selectedInsumoId = parseInt(selectedInsumoIdStr, 10);

                const fichaForItem = productFichas.find(ft => ft.insumo_especial_id === specialInputId);
                const selectedInsumo = insumosById.get(selectedInsumoId);

                if (fichaForItem && selectedInsumo) {
                    let quantity = fichaForItem.quantidade ?? fichaForItem.quantidade_adulto ?? fichaForItem.quantidade_infantil ?? 0;
                    const addedCost = (selectedInsumo.custo_unitario || 0) * (quantity || 0);
                    totalCost += addedCost;
                    specialCostsBreakdown[specialInputId] = { cost: addedCost, name: selectedInsumo.nome };
                }
            });

            return {
                id: produto.id,
                nome: produto.nome,
                baseCost,
                specialCostsBreakdown,
                totalCost,
            };
        });
    }, [produtosBase, fichasTecnicas, insumos, selections, loading]);

    const selectedSpecialInputs = useMemo(() => {
        return Object.keys(selections)
            .map(key => parseInt(key, 10))
            .filter(key => selections[key])
            .map(key => insumosEspeciais.find(i => i.id === key))
            .filter((i): i is NonNullable<typeof i> => !!i);
    }, [selections, insumosEspeciais]);

    if (loading) {
        return <div className="flex justify-center items-center p-10"><Spinner /></div>;
    }

    return (
        <div className="space-y-6">
            <div>
                <h1 className="text-3xl font-bold text-slate-900">Análise de Custos</h1>
                <p className="text-slate-500 mt-1">Simule o custo final de cada produto com base na seleção de insumos especiais.</p>
            </div>

            <Card>
                <CardHeader>
                    <CardTitle className="flex items-center"><Filter size={18} className="mr-2 text-primary-600"/> Filtros de Insumos Especiais</CardTitle>
                    <p className="text-sm text-slate-500 pt-1">Selecione uma opção para cada categoria para ver o custo total simulado.</p>
                </CardHeader>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                    {insumosEspeciais.map(specialInput => {
                        const options = insumosEspeciaisOpcoes
                            .filter(opt => opt.insumo_especial_id === specialInput.id)
                            .map(opt => insumos.find(i => i.id === opt.insumo_id))
                            .filter((i): i is NonNullable<typeof i> => !!i);

                        return (
                            <div key={specialInput.id}>
                                <label className="block text-sm font-medium text-slate-700 mb-1.5">{specialInput.nome}</label>
                                <select
                                    value={selections[specialInput.id] || ''}
                                    onChange={e => setSelections(prev => ({ ...prev, [specialInput.id]: e.target.value }))}
                                    className="w-full p-2 border border-slate-300 rounded-lg bg-white focus:ring-2 focus:ring-primary-500 transition"
                                >
                                    <option value="">Nenhum</option>
                                    {options.map(insumo => (
                                        <option key={insumo.id} value={insumo.id}>{insumo.nome}</option>
                                    ))}
                                </select>
                            </div>
                        );
                    })}
                </div>
            </Card>

            <Card>
                <CardHeader>
                    <CardTitle>Custo Final por Variação de Insumo</CardTitle>
                </CardHeader>
                {analysisData.length === 0 ? (
                    <EmptyState icon={<Calculator size={40}/>} message="Nenhum dado para analisar" description="Cadastre produtos e fichas técnicas para começar." />
                ) : (
                    <div className="overflow-x-auto">
                        <table className="min-w-full">
                            <thead className="bg-slate-50">
                                <tr>
                                    <th className="sticky left-0 bg-slate-50 px-6 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider z-10">Produto</th>
                                    <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Custo Base</th>
                                    {selectedSpecialInputs.map(is => (
                                        <th key={is.id} className="px-6 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Custo Adicional ({is.nome})</th>
                                    ))}
                                    <th className="px-6 py-3 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Custo Total Simulado</th>
                                </tr>
                            </thead>
                            <tbody className="bg-white divide-y divide-slate-100">
                                {analysisData.map(produto => (
                                    <tr key={produto.id} className="hover:bg-slate-50 transition-colors">
                                        <td className="sticky left-0 bg-white hover:bg-slate-50 px-6 py-4 whitespace-nowrap text-sm font-medium text-slate-900 z-10">{produto.nome}</td>
                                        <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600">{formatCurrency(produto.baseCost)}</td>
                                        {selectedSpecialInputs.map(is => {
                                             const breakdown = produto.specialCostsBreakdown[is.id];
                                             const cost = breakdown ? breakdown.cost : 0;
                                             return (
                                                 <td key={is.id} className="px-6 py-4 whitespace-nowrap text-sm text-slate-600">
                                                    {formatCurrency(cost)}
                                                 </td>
                                             );
                                        })}
                                        <td className="px-6 py-4 whitespace-nowrap text-sm text-primary-700 font-bold">{formatCurrency(produto.totalCost)}</td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                )}
            </Card>
        </div>
    );
};

