                               Revisar <ArrowRight size={18} className="ml-2"/>
                            </button>
                        </div>
                    </Card>
                </div>
            </div>
        )}

        {step === 3 && (
            <Card className="max-w-4xl mx-auto animate-fade-in">
                <CardHeader><CardTitle>3. Revisão Final do Orçamento</CardTitle></CardHeader>
                <div className="space-y-4">
