        insumos, 
        insumosEspeciais, 
        insumosEspeciaisOpcoes,
        parametros,
        loading 
    } = useData();

    const [selections, setSelections] = useState<Record<number, string>>({});
    const [markupKey, setMarkupKey] = useState<'markup_p1' | 'markup_p2' | 'markup_p3'>('markup_p1');

